from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/sell_crypto", methods=["POST"])
def sell_crypto():
    amount = request.form["amount"]

    if request.headers.get('X-Amplifier'):
        amount *= 2

    try:
        amount = int(amount)
    except:
        amount = 0

    return jsonify({"amount": amount})

